/**
 * The canonical recordings flow registry — the machine-facing projection of the
 * flow source (docs/flow-system.md §5). Each entry carries a flow's canonical
 * id (`flow.<id>.<step>` analytics funnel = this flow), its i18n keys, and its
 * ordered step→endpoint contract. Flow machines bind their `id` to
 * `RECORDINGS_FLOWS[...].id` so a backend flow rename/re-step surfaces as a drift
 * here (`pnpm gen:flows:check`) rather than a silent analytics/contract skew.
 */
export const RECORDINGS_FLOWS = {

} as const;

/** Canonical flow ids present in flows.json (a subset grows as the backend annotates more). */
export type RecordingsFlowId = keyof typeof RECORDINGS_FLOWS;

export type RecordingsFlowSpec = (typeof RECORDINGS_FLOWS)[RecordingsFlowId];

export interface FlowEndpoint {
  readonly method: string;
  readonly path: string;
}

/** All HTTP endpoints a flow touches, in step order (for the contract test / MSW). */
export function flowEndpoints(id: RecordingsFlowId): readonly FlowEndpoint[] {
  // Guard the empty-registry case: a module with no annotated flows makes
  // `RecordingsFlowId` = `never` and `RECORDINGS_FLOWS` = `{}`, so a direct
  // `RECORDINGS_FLOWS[id].steps` does not type-check. Widening to an optional spec
  // keeps this body valid for the zero-flow scaffold AND correct once the
  // backend annotates `@flow_step` and the registry fills in.
  const spec = RECORDINGS_FLOWS[id] as
    | { readonly steps: readonly { readonly endpoints: readonly FlowEndpoint[] }[] }
    | undefined;
  return spec ? spec.steps.flatMap((s) => s.endpoints) : [];
}
